export const PLASMA_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;       // seconds, monotonically increasing; range [0, inf)
uniform vec2 uResolution;  // framebuffer size in pixels; both components > 0
uniform vec3 uColorA;      // first palette color, linear-ish RGB in [0, 1]
uniform vec3 uColorB;      // second palette color, linear-ish RGB in [0, 1]
uniform float uSpeed;      // animation rate multiplier; 0 freezes the field
uniform float uScale;      // spatial frequency; higher = more, tighter cells

in highp vec2 vUv;
out vec4 oColor;

void main() {
  // Aspect-correct, screen-centered coordinates (matches nebula.frag): divide
  // by the height so uScale reads the same regardless of aspect ratio.
  vec2 fragCoord = vUv * uResolution;
  vec2 uv = (fragCoord - 0.5 * uResolution) / uResolution.y;

  float t = uTime * uSpeed;

  // Classic demoscene plasma: a few sines of position and time. The radial
  // term (length(uv)) gives the field an organic, non-grid-aligned drift.
  float v = sin(uv.x * uScale + t);
  v += sin(uv.y * uScale + t * 0.8);
  v += sin((uv.x + uv.y) * uScale * 0.7 + t * 1.3);
  v += sin(length(uv) * uScale * 1.2 - t);

  // v ranges roughly [-4, 4]; fold through sin to a smooth [0, 1] mix factor.
  float mixT = 0.5 + 0.5 * sin(v);

  // Opaque procedural background; the person is composited over it downstream.
  oColor = vec4(mix(uColorA, uColorB, mixT), 1.0);
}
`;

export const KALEIDOSCOPE_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;       // seconds, monotonically increasing; range [0, inf)
uniform vec2 uResolution;  // framebuffer size in pixels; both components > 0
uniform vec3 uColorA;      // base palette color (also the calm midpoint pole)
uniform vec3 uColorB;      // second palette color
uniform vec3 uColorC;      // accent color, layered over the A/B field
uniform float uSegments;   // mirror segment count; floor()ed, clamped >= 3
uniform float uSpeed;      // source-field drift rate; 0 freezes the pattern
uniform float uRotate;     // whole-field rotation rate; sign sets direction
uniform float uZoom;       // pattern scale; higher = more rings of detail
uniform float uCalm;       // 0..1 eases contrast at frame center (face zone)

in highp vec2 vUv;
out vec4 oColor;

const float TAU = 6.28318530718;

void main() {
  // Aspect-correct, screen-centered coordinates (matches plasma/nebula).
  vec2 fragCoord = vUv * uResolution;
  vec2 uv = (fragCoord - 0.5 * uResolution) / uResolution.y;
  float centerDist = length(uv);

  // Whole-field rotation: the slow "turning the scope" motion.
  float ra = uTime * uRotate;
  float cs = cos(ra);
  float sn = sin(ra);
  uv = mat2(cs, -sn, sn, cs) * uv;

  // Mirrored polar fold. The 1e-5 nudge keeps atan() off the undefined (0,0)
  // input under Metal; it is far below one pixel at any resolution.
  float r = centerDist * uZoom * (1.0 + 0.06 * sin(uTime * 0.23));
  float seg = TAU / max(3.0, floor(uSegments));
  float a = atan(uv.y, uv.x + 1e-5);
  a = mod(a, seg);
  a = abs(a - seg * 0.5);
  vec2 p = r * vec2(cos(a), sin(a));

  float t = uTime * uSpeed;

  // Drifting source field, plasma-class: a few sines of folded position and
  // time. The off-axis moving center in the length() term keeps the pattern
  // evolving (non-repeating) rather than pulsing in place.
  float f1 = sin(p.x * 6.0 + t)
      + sin((p.x + p.y) * 4.2 - t * 0.7)
      + sin(length(p - vec2(0.9 + 0.25 * sin(t * 0.31), 0.0)) * 7.0 + t * 1.1);
  float f2 = sin(p.y * 5.0 - t * 0.9 + sin(p.x * 3.1 + t * 0.4));
  float m1 = 0.5 + 0.5 * sin(f1);
  float m2 = smoothstep(0.25, 0.9, 0.5 + 0.5 * sin(f2 + f1 * 0.5));

  vec3 color = mix(uColorA, uColorB, m1);
  color = mix(color, uColorC, m2 * 0.65);

  // Thin darkening along both mirror lines sells the cut-glass facets.
  float seam = smoothstep(0.035, 0.0, abs(a - seg * 0.5)) + smoothstep(0.035, 0.0, a);
  color *= 1.0 - 0.18 * seam;

  // uCalm: ease toward the palette midpoint near frame center. Spatial-only
  // (never scales time per pixel, which would shear the field across the
  // falloff ring).
  vec3 mid = 0.5 * (uColorA + uColorB);
  float calm = uCalm * (1.0 - smoothstep(0.15, 0.62, centerDist));
  color = mix(color, mid, calm * 0.6);

  // Opaque procedural background; the person is composited over it downstream.
  oColor = vec4(color, 1.0);
}
`;

export const NEO_MEMPHIS_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;       // seconds, monotonically increasing; range [0, inf)
uniform vec2 uResolution;  // framebuffer size in pixels; both components > 0
uniform vec3 uBgColor;     // field color behind the shapes
uniform vec3 uColorA;      // shape palette color 1
uniform vec3 uColorB;      // shape palette color 2
uniform vec3 uColorC;      // shape palette color 3
uniform float uScale;      // hero-grid cells across frame height
uniform float uDensity;    // probability a cell draws its shape, 0..1
uniform float uOutline;    // probability a shape renders outlined, 0..1
uniform float uDrift;      // scroll + rotation rate; 0 freezes
uniform float uCalm;       // 0..1 fades shapes near frame center (face zone)

in highp vec2 vUv;
out vec4 oColor;

const float TAU = 6.28318530718;
// Antialias half-width in cell units; ~1px at the default pitch.
const float AA = 0.012;

float hash21(vec2 p) {
  p = fract(p * vec2(234.34, 435.345));
  p += dot(p, p + 34.23);
  return fract(p.x * p.y);
}

float sdBox(vec2 p, vec2 b) {
  vec2 d = abs(p) - b;
  return length(max(d, vec2(0.0))) + min(max(d.x, d.y), 0.0);
}

// iq's equilateral triangle, point up, circumradius r.
float sdTriangle(vec2 p, float r) {
  const float k = 1.7320508;
  p.x = abs(p.x) - r;
  p.y = p.y + r / k;
  if (p.x + k * p.y > 0.0) {
    p = vec2(p.x - k * p.y, -k * p.x - p.y) * 0.5;
  }
  p.x -= clamp(p.x, -2.0 * r, 0.0);
  return -length(p) * sign(p.y);
}

// One cell layer: returns the shape coverage and writes its color.
// luv is the layer's scrolled cell-space coordinate; backfill restricts the
// shape menu to dots and crosses and draws smaller.
float memphisCell(vec2 luv, float seed, float backfill, float t, out vec3 shapeColor) {
  vec2 id = floor(luv);
  vec2 gv = fract(luv) - 0.5;
  float h = hash21(id + seed);
  shapeColor = uBgColor;
  // Density gate: empty cells cost one hash.
  if (h > uDensity) return 0.0;

  float h2 = fract(h * 57.31);
  float h3 = fract(h * 113.77);
  float h4 = fract(h * 431.13);
  float h5 = fract(h * 891.71);

  // Per-cell slow spin and a small bob; both bounded so the shape stays
  // inside its cell (max extent 0.34 + 0.04 < 0.5).
  float ang = h2 * TAU + t * (h3 - 0.5) * 0.8;
  float cs = cos(ang);
  float sn = sin(ang);
  gv -= 0.04 * vec2(sin(t * 0.6 + h * TAU), cos(t * 0.8 + h * TAU));
  gv = mat2(cs, -sn, sn, cs) * gv;

  float r = mix(0.14, 0.30, h3) * mix(1.0, 0.6, backfill);
  float pick = h4 * 6.0;
  float d;
  if (backfill > 0.5) {
    // Backfill texture: dots and crosses only.
    d = (pick < 3.0)
        ? length(gv) - r * 0.45
        : min(sdBox(gv, vec2(r, r * 0.22)), sdBox(gv, vec2(r * 0.22, r)));
  } else if (pick < 1.0) {
    d = length(gv) - r;                                   // disc
  } else if (pick < 2.0) {
    d = abs(length(gv) - r * 0.8) - r * 0.18;             // ring
  } else if (pick < 3.0) {
    d = sdTriangle(gv, r);                                // triangle
  } else if (pick < 4.0) {
    d = min(sdBox(gv, vec2(r, r * 0.24)), sdBox(gv, vec2(r * 0.24, r))); // cross
  } else if (pick < 5.0) {
    d = sdBox(gv, vec2(r * 0.78, r * 0.78));              // box
  } else {
    // Squiggle: a sine-displaced band, clipped to its run length.
    d = max(abs(gv.y - 0.4 * r * sin(gv.x / r * 6.5)) - r * 0.17, abs(gv.x) - r);
  }

  float fill = smoothstep(AA, -AA, d);
  float ring = smoothstep(AA, -AA, abs(d + r * 0.06) - r * 0.09);
  float m = (h5 < uOutline) ? ring : fill;

  float colorPick = fract(h * 769.23) * 3.0;
  shapeColor = (colorPick < 1.0) ? uColorA : (colorPick < 2.0) ? uColorB : uColorC;
  return m;
}

void main() {
  // Aspect-correct, screen-centered coordinates (matches plasma/nebula).
  vec2 fragCoord = vUv * uResolution;
  vec2 uv = (fragCoord - 0.5 * uResolution) / uResolution.y;
  float centerDist = length(uv);

  float t = uTime * uDrift;
  vec3 color = uBgColor;
  vec3 shapeColor;

  // Backfill layer first (under the hero shapes): smaller, denser, dimmer.
  vec2 luv1 = uv * uScale * 2.3 + vec2(t * 0.045, t * -0.03) + 51.7;
  float m1 = memphisCell(luv1, 7.0, 1.0, t, shapeColor);
  color = mix(color, mix(uBgColor, shapeColor, 0.55), m1);

  // Hero layer: the big shapes, scrolling the other way.
  vec2 luv0 = uv * uScale + vec2(t * -0.06, t * 0.04);
  float m0 = memphisCell(luv0, 0.0, 0.0, t, shapeColor);

  // uCalm: fade shapes (not the field) near frame center.
  float calm = 1.0 - uCalm * (1.0 - smoothstep(0.15, 0.62, centerDist));
  color = mix(color, shapeColor, m0 * calm);

  // Opaque procedural background; the person is composited over it downstream.
  oColor = vec4(color, 1.0);
}
`;

export const HALFTONE_WAVES_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;       // seconds, monotonically increasing; range [0, inf)
uniform vec2 uResolution;  // framebuffer size in pixels; both components > 0
uniform vec3 uPaper;       // field color (behind the dots)
uniform vec3 uInk;         // dot color
uniform float uPitch;      // dot-grid cells across frame height
uniform float uDotSize;    // base dot radius in cell units, 0..0.5
uniform float uWaveAmp;    // radius modulation depth, 0..1
uniform float uSpeed;      // wave travel rate; 0 freezes
uniform float uShape;      // dot shape: 0 diamond, 1 circle, 2 square
uniform float uAngle;      // wave direction, radians
uniform float uCalm;       // 0..1 eases the waves at frame center (face zone)

in highp vec2 vUv;
out vec4 oColor;

// Antialias half-width in cell units; ~1px at the default pitch.
const float AA = 0.06;

void main() {
  // Aspect-correct, screen-centered coordinates (matches plasma/nebula).
  vec2 fragCoord = vUv * uResolution;
  vec2 uv = (fragCoord - 0.5 * uResolution) / uResolution.y;
  float centerDist = length(uv);

  vec2 luv = uv * uPitch;
  vec2 id = floor(luv);
  vec2 gv = fract(luv) - 0.5;
  // Wave phase is sampled at the CELL CENTER so a dot's radius is uniform
  // across its own pixels (true halftone, not a warped field).
  vec2 c = (id + 0.5) / uPitch;

  float t = uTime * uSpeed;
  vec2 dir1 = vec2(cos(uAngle), sin(uAngle));
  vec2 dir2 = vec2(cos(uAngle + 2.2), sin(uAngle + 2.2));
  // Two traveling waves at incommensurate frequencies: interference patterns
  // that drift forever without visibly repeating.
  float w = 0.5 + 0.25 * sin(dot(c, dir1) * 3.1 + t) + 0.25 * sin(dot(c, dir2) * 4.7 - t * 0.77);

  // uCalm: flatten the modulation toward its midpoint near frame center.
  float calm = uCalm * (1.0 - smoothstep(0.15, 0.62, centerDist));
  w = mix(w, 0.5, calm);

  float radius = uDotSize * mix(1.0 - uWaveAmp, 1.0 + uWaveAmp, w);

  // Blended distance metric, pow-free (variable-exponent pow lowers to
  // exp2+log2 on mobile): diamond (L1) -> circle (L2) -> square (Linf).
  vec2 q = abs(gv);
  float dDiamond = (q.x + q.y) * 0.7071;
  float dCircle = length(q);
  float dSquare = max(q.x, q.y);
  float d = (uShape < 1.0)
      ? mix(dDiamond, dCircle, clamp(uShape, 0.0, 1.0))
      : mix(dCircle, dSquare, clamp(uShape - 1.0, 0.0, 1.0));

  float m = smoothstep(radius + AA, radius - AA, d);
  vec3 color = mix(uPaper, uInk, m);

  // Opaque procedural background; the person is composited over it downstream.
  oColor = vec4(color, 1.0);
}
`;

export const AURORA_SILK_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;       // seconds, monotonically increasing; range [0, inf)
uniform vec2 uResolution;  // framebuffer size in pixels; both components > 0
uniform vec3 uColorLow;    // gradient color at the flow's low side
uniform vec3 uColorHigh;   // gradient color at the flow's high side
uniform vec3 uRibbonColor; // ribbon tint; shades blend toward uColorHigh
uniform float uRibbons;    // visible ribbon count, 1..5 (MAX_RIBBONS)
uniform float uSoftness;   // ribbon edge softness, 0..1
uniform float uAngle;      // flow direction, radians
uniform float uSpeed;      // drift rate; 0 freezes
uniform float uStyle;      // 0 flat paper-cut .. 1 glowing silk
uniform float uCalm;       // 0..1 eases ribbons at frame center (face zone)

in highp vec2 vUv;
out vec4 oColor;

const int MAX_RIBBONS = 5;

float hash11(float n) {
  return fract(sin(n) * 43758.5453123);
}

// 1D value noise: smooth, cheap, non-repeating drift source per ribbon.
float vnoise(float x, float seed) {
  float i = floor(x);
  float f = fract(x);
  float a = hash11(i + seed);
  float b = hash11(i + 1.0 + seed);
  return mix(a, b, f * f * (3.0 - 2.0 * f));
}

void main() {
  // Aspect-correct, screen-centered coordinates (matches plasma/nebula).
  vec2 fragCoord = vUv * uResolution;
  vec2 uv = (fragCoord - 0.5 * uResolution) / uResolution.y;
  float centerDist = length(uv);

  // Rotate into flow space: ribbons run along q.x, stack along q.y.
  float cs = cos(uAngle);
  float sn = sin(uAngle);
  vec2 q = mat2(cs, -sn, sn, cs) * uv;

  float t = uTime * uSpeed;

  // Base: soft two-stop gradient across the stacking axis, with a slow
  // breathing tilt so the field is alive even at uRibbons = 0 edge cases.
  float g = clamp(q.y * 0.85 + 0.5 + 0.04 * sin(t * 0.17), 0.0, 1.0);
  vec3 color = mix(uColorLow, uColorHigh, g);

  float ribbons = clamp(uRibbons, 0.0, float(MAX_RIBBONS));
  float calm = 1.0 - uCalm * (1.0 - smoothstep(0.15, 0.62, centerDist));

  for (int i = 0; i < MAX_RIBBONS; i++) {
    float fi = float(i);
    if (fi >= ribbons) break;

    // Stack centers across the frame, each with its own slow vertical sway.
    float center = -0.42 + 0.84 * (fi + 0.5) / ribbons + 0.07 * sin(t * 0.19 + fi * 1.7);
    // Lateral warp: low-frequency noise plus one sine, per-ribbon phase and
    // rate so the bands never move in lockstep.
    float warp = (vnoise(q.x * 1.4 + t * (0.1 + 0.04 * fi), fi * 17.0) - 0.5) * 0.5
        + 0.1 * sin(q.x * 2.3 + t * (0.26 + 0.06 * fi) + fi * 2.1);
    float dy = abs(q.y - (center + warp));

    float widthR = mix(0.06, 0.15, hash11(fi * 7.3 + 1.0));
    float soft = mix(0.008, widthR * 1.6, uSoftness);
    float band = (1.0 - smoothstep(widthR - soft, widthR + soft, dy)) * calm;

    // Ribbon shade: deeper tints at the back of the stack.
    vec3 rc = mix(uRibbonColor, uColorHigh, fi / float(MAX_RIBBONS) * 0.6);

    // uStyle blends two composites of the same band: flat paint-over vs
    // additive glow.
    vec3 flat_ = mix(color, rc, band * 0.85);
    vec3 glow = color + rc * band * 0.4;
    color = mix(flat_, glow, uStyle);
  }

  // Opaque procedural background; the person is composited over it downstream.
  oColor = vec4(color, 1.0);
}
`;

export const OUTRUN_GRID_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;        // seconds, monotonically increasing; range [0, inf)
uniform vec2 uResolution;   // framebuffer size in pixels; both components > 0
uniform vec3 uSkyTop;       // sky gradient color at the top of frame
uniform vec3 uSkyHorizon;   // sky gradient color at the horizon
uniform vec3 uSunTop;       // sun gradient color at its top
uniform vec3 uSunBottom;    // sun gradient color at its bottom
uniform vec3 uGridColor;    // neon grid line tint (also the horizon seam)
uniform float uGridDensity; // grid cells across the floor; higher = finer
uniform float uGridGlow;    // line glow width/softness, 0..1
uniform float uSpeed;       // grid scroll rate toward the viewer; 0 freezes
uniform float uSunSize;     // sun radius in vUv.y units
uniform float uSunBands;    // horizontal slit count cut into the sun's lower half
uniform float uHorizon;     // horizon height in vUv.y, 0..1 (floor below, sky above)
uniform float uCalm;        // 0..1 eases the additive glow at frame center (face zone)

in highp vec2 vUv;
out vec4 oColor;

void main() {
  float aspect = uResolution.x / uResolution.y;
  float fx = (vUv.x - 0.5) * aspect; // aspect-correct, screen-centered x
  float fy = vUv.y;                  // 0 bottom .. 1 top
  float h = clamp(uHorizon, 0.05, 0.95);

  // Ease additive glow near the frame center (the subject's face sits there).
  float calm = 1.0 - uCalm * (1.0 - smoothstep(0.18, 0.62, length(vec2(fx, fy - 0.5))));

  vec3 col;

  if (fy > h) {
    // --- SKY ---
    float skyT = (fy - h) / (1.0 - h); // 0 at horizon, 1 at the top of frame
    col = mix(uSkyHorizon, uSkyTop, skyT);

    // --- SUN --- centered just above the horizon so its lower arc sinks below
    // it and is occluded by the floor (the half-set sun, for free).
    float sunCY = h + uSunSize * 0.55;
    vec2 sd = vec2(fx, fy - sunCY);
    float r = length(sd) / max(uSunSize, 1e-3); // normalized radius, 1 at the edge

    // Soft glow halo bleeding into the sky around the disc.
    float halo = exp(-max(r - 1.0, 0.0) * 5.5);
    col += uSunTop * halo * 0.55 * calm;

    // Sun body: vertical gradient, with horizontal bands cut from the lower half
    // (each gap thickening toward the bottom, the iconic retrowave slit pattern).
    float disc = smoothstep(1.0, 0.985, r);
    float vy = clamp(sd.y / max(uSunSize, 1e-3) * 0.5 + 0.5, 0.0, 1.0);
    vec3 sunCol = mix(uSunBottom, uSunTop, vy);

    float below = max(-sd.y / max(uSunSize, 1e-3), 0.0); // 0 above center, grows downward
    float slit = fract(below * uSunBands);
    float gapW = clamp(below, 0.0, 1.0) * 0.85;          // gap fraction grows downward
    float cut = step(slit, gapW) * smoothstep(0.04, 0.12, below); // keep upper sun whole
    float sunBody = disc * (1.0 - cut);

    col = mix(col, sunCol, sunBody);
  } else {
    // --- FLOOR --- perspective grid. Guard the divide; shade only below horizon.
    float depth = 1.0 / max(h - fy, 1.5e-3); // large near the horizon
    float depthMin = 1.0 / h;                // depth at the very front (fy = 0)
    vec2 fuv = vec2(fx * depth, depth + uTime * uSpeed);

    // Distance to the nearest grid line in each axis (0 on a line, 0.5 mid-cell).
    vec2 f = fract(fuv * uGridDensity);
    vec2 lineDist = min(f, 1.0 - f);
    float d = min(lineDist.x, lineDist.y);

    // Analytic neon glow; uGridGlow widens/softens the line.
    float line = exp(-d * d * (220.0 / max(uGridGlow, 0.05)));

    // Distance fog: fade lines out before the horizon-compression aliasing zone,
    // which also gives the authentic converging-to-fog look.
    float fog = clamp(1.0 - (depth - depthMin) / (depthMin * 14.0), 0.0, 1.0);
    fog *= fog;

    vec3 floorBase = mix(vec3(0.0), uSkyHorizon * 0.16, fog * 0.6);
    col = floorBase + uGridColor * line * fog * calm;
  }

  // Glowing horizon seam where floor meets sky.
  float seam = exp(-abs(fy - h) * 90.0);
  col += uGridColor * seam * 0.5 * calm;

  oColor = vec4(col, 1.0);
}
`;

export const CLOUDS_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;
uniform vec2 uResolution;
uniform vec3 uSkyLowColor;
uniform vec3 uSkyHighColor;
uniform vec3 uCloudLightColor;
uniform vec3 uCloudDarkColor;
uniform float uExposure;
uniform float uStepSize;
uniform float uCloudSpeed;
uniform float uCloudScale;
uniform float uDensity;
uniform float uCoverage;
uniform float uSoftness;

in highp vec2 vUv;
out vec4 oColor;

// STEPS must stay a compile-time constant (GLSL ES loop bound).
// 32 (was 48; issue #37): the distance-growing step in main() keeps the
// marched range, so fewer steps buys speed instead of clipping the horizon.
#define STEPS 32

float hash(vec3 p) {
    p = fract(p * 0.3183099 + 0.1);
    p *= 17.0;
    return fract(p.x * p.y * p.z * (p.x + p.y + p.z));
}

float rand(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}

float noise(vec3 p) {
    vec3 i = floor(p);
    vec3 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    return mix(
        mix(
            mix(hash(i + vec3(0,0,0)), hash(i + vec3(1,0,0)), f.x),
            mix(hash(i + vec3(0,1,0)), hash(i + vec3(1,1,0)), f.x),
            f.y),
        mix(
            mix(hash(i + vec3(0,0,1)), hash(i + vec3(1,0,1)), f.x),
            mix(hash(i + vec3(0,1,1)), hash(i + vec3(1,1,1)), f.x),
            f.y),
        f.z);
}

// 4 octaves (was 5; issue #37): the 5th octave is fine wisp detail the
// smoothstep(uCoverage, uCoverage + uSoftness, n) threshold mostly eats; each
// octave is 8 hash() calls per sample, so this is a flat -20% on the march.
float fbm(vec3 p) {
    float v = 0.0;
    float a = 0.5;
    for (int i = 0; i < 4; i++) {
        v += a * noise(p);
        p *= 2.03;
        a *= 0.5;
    }
    return v;
}

float cloudDensity(vec3 p) {
    p += vec3(uTime * uCloudSpeed, 0.0, uTime * uCloudSpeed * 0.35);
    // Outside the slab the height mask is 0, so the sample is 0; bail before fbm.
    if (p.y <= 0.0 || p.y >= 3.0) return 0.0;
    float n = fbm(p * uCloudScale);
    float bottom = smoothstep(0.0, 0.7, p.y);
    float top = smoothstep(3.0, 1.2, p.y);
    float heightMask = bottom * top;
    float cloud = smoothstep(uCoverage, uCoverage + uSoftness, n);
    return cloud * heightMask;
}

void main() {
    vec2 fragCoord = vUv * uResolution;
    vec2 uv = (fragCoord - 0.5 * uResolution) / uResolution.y;
    vec3 ro = vec3(0.0, 1.2, -4.0);
    vec3 rd = normalize(vec3(uv, 1.5));
    float skyGradient = clamp(rd.y * 0.5 + 0.5, 0.0, 1.0);
    vec3 skyColor = mix(uSkyLowColor, uSkyHighColor, skyGradient);
    vec3 accum = vec3(0.0);
    float alpha = 0.0;
    float t = rand(fragCoord) * uStepSize;
    for (int i = 0; i < STEPS; i++) {
        vec3 p = ro + rd * t;
        // The slab is crossed monotonically in t; once past it, all samples are 0.
        if (rd.y > 0.0 && p.y >= 3.0) break;
        if (rd.y < 0.0 && p.y <= 0.0) break;
        float d = cloudDensity(p);
        // Distance-growing step (issue #37): far clouds are small on screen and
        // tolerate coarser sampling, so the step stretches with t. 32 growing
        // steps reach slightly past where 48 uniform steps did, spending the
        // samples up close where banding would show. growth also scales the
        // per-sample opacity so optical depth per unit distance stays consistent
        // with the uniform-step tuning the presets were dialed against.
        float growth = 1.0 + t * 0.15;
        if (d > 0.01) {
            float light = smoothstep(0.4, 2.8, p.y);
            vec3 sampleColor = mix(uCloudDarkColor, uCloudLightColor, light);
            float a = min(d * uDensity * growth, 1.0);
            accum += (1.0 - alpha) * sampleColor * a;
            alpha += (1.0 - alpha) * a;
        }
        t += uStepSize * growth;
        if (alpha > 0.95) break;
    }
    vec3 color = mix(skyColor, accum, alpha);
    color *= uExposure;
    color = pow(color, vec3(0.9));
    oColor = vec4(color, 1.0);
}
`;

export const NEBULA_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;          // seconds, monotonically increasing; range [0, inf)
uniform vec2 uResolution;     // framebuffer size in pixels; both components > 0
uniform vec3 uColor;          // overall tint / color grade; [1,1,1] = untinted
uniform float uBrightness;    // final glow multiplier; 1.0 = stock
uniform float uSpeed;         // drift + rotation rate; 1.0 = stock, 0 freezes
uniform float uTwinkleSpeed;  // star color-cycle rate; 1.0 = stock
uniform float uScale;         // starfield zoom / density; >1 = more, smaller stars
uniform float uStarGlow;      // star-core size; 1.0 = stock

in highp vec2 vUv;
out vec4 oColor;

const float PI = 3.14159265;
const float MIN_DIVIDE = 64.0;
const float MAX_DIVIDE = 0.01;
// Number of stacked starfield layers. Compile-time constant so the layer
// loop has a fixed integer bound (cross-compile-safe; no float loop counter).
// 8 (was 12) for low-end-mobile cost (issue #39); the work is linear in the
// count and dimByDensity rebalances per-star brightness automatically.
const int STARFIELD_LAYERS_COUNT = 8;

mat2 Rotate(float angle) {
  float s = sin(angle);
  float c = cos(angle);
  return mat2(c, -s, s, c);
}

float Star(vec2 uv, float flaresize, float rotAngle, float randomN) {
  float d = length(uv);
  // The concentric fade at the bottom is exactly 0 for d >= 1.0; the star is
  // invisible there, so skip everything (issue #39: a large share of the 3x3
  // neighbor sweep lands outside this radius; the cull is output-identical).
  if (d >= 1.0) return 0.0;
  // Star core. Guard the division: length(uv) can be exactly 0 at a cell
  // center, which yields inf/NaN under Metal. max(d, 1e-4) caps the core
  // brightness without visibly changing the look (the concentric
  // smoothstep fade below already clamps it).
  float starcore = 0.05 * uStarGlow / max(d, 1e-4);
  // Flares exist only on the brightest stars: flaresize is exactly 0 below the
  // smoothstep(0.9, 1.0, size) knee (~90% of cells), and both Rotates feed
  // nothing but the flares. Skipping the block is output-identical, and
  // flaresize is constant per cell, so the branch is coherent (issue #39).
  if (flaresize > 0.0) {
    uv *= Rotate(-2.0 * PI * rotAngle);
    float flareMax = 1.0;

    // flares
    float starflares = max(0.0, flareMax - abs(uv.x * uv.y * 3000.0));
    starcore += starflares * flaresize;
    uv *= Rotate(PI * 0.25);
    starflares = max(0.0, flareMax - abs(uv.x * uv.y * 3000.0));
    starcore += starflares * 0.3 * flaresize;
  }
  // light can't go forever, fade it concentrically.
  starcore *= smoothstep(1.0, 0.05, d);
  return starcore;
}

float PseudoRandomizer(vec2 p) {
  // not really random, but it looks random.
  p = fract(p * vec2(123.45, 345.67));
  p += dot(p, p + 45.32);
  return fract(p.x * p.y);
}

vec3 StarFieldLayer(vec2 uv, float rotAngle) {
  vec3 col = vec3(0.0);

  vec2 gv = fract(uv) - 0.5;
  vec2 id = floor(uv);

  float deltaTimeTwinkle = uTime * 0.35 * uTwinkleSpeed;

  // sweep the 8 neighbors plus the home cell so stars are not clipped at
  // cell borders. Constant 3x3 bounds.
  for (int y = -1; y <= 1; y++) {
    for (int x = -1; x <= 1; x++) {
      vec2 offset = vec2(float(x), float(y));

      float randomN = PseudoRandomizer(id + offset); // 0..1
      float randoX = randomN - 0.5;
      float randoY = fract(randomN * 45.0) - 0.5;
      vec2 randomPosition = gv - offset - vec2(randoX, randoY);
      // fract trick: random sizes
      float size = fract(randomN * 1356.33);
      float flareSwitch = smoothstep(0.9, 1.0, size);
      float star = Star(randomPosition, flareSwitch, rotAngle, randomN);

      // fract trick: random colors
      float randomStarColorSeed = fract(randomN * 2150.0) * (3.0 * PI) * deltaTimeTwinkle;
      vec3 color = sin(vec3(0.7, 0.3, 0.9) * randomStarColorSeed);

      // compress
      color = color * (0.4 * sin(deltaTimeTwinkle)) + 0.6;
      // filter
      color = color * vec3(1.0, 0.1, 0.9 + size);
      float dimByDensity = 15.0 / float(STARFIELD_LAYERS_COUNT);
      col += star * size * color * dimByDensity;
    }
  }

  return col;
}

void main() {
  // ShaderToy fragCoord, reconstructed from vUv (see header).
  vec2 fragCoord = vUv * uResolution;

  // Normalized pixel coordinates centered at screen middle.
  vec2 uv = (fragCoord - 0.5 * uResolution.xy) / uResolution.y;

  float deltaTime = uTime * 0.01 * uSpeed;

  vec3 col = vec3(0.0);

  float rotAngle = deltaTime * 0.09;

  // Layer accumulation. Integer-counted loop replacing the original
  // \`for (float i = 0.0; i < 1.0; i += 1.0/COUNT)\`. With n in [0, COUNT),
  // i = n/COUNT reproduces the exact same {0, 1/N, 2/N, ...} sequence and
  // the same iteration count, so visual output is unchanged; only the loop
  // form is cross-compile-safe.
  for (int n = 0; n < STARFIELD_LAYERS_COUNT; n++) {
    float i = float(n) / float(STARFIELD_LAYERS_COUNT);
    float layerDepth = fract(i + deltaTime);
    float layerScale = mix(MIN_DIVIDE, MAX_DIVIDE, layerDepth);
    float layerFader = layerDepth * smoothstep(0.1, 1.1, layerDepth);
    float layerOffset = i * (3430.0 + fract(i));
    mat2 layerRot = Rotate(rotAngle * i * -10.0);
    uv *= layerRot;
    vec2 starfieldUv = uv * layerScale * uScale + layerOffset;
    col += StarFieldLayer(starfieldUv, rotAngle) * layerFader;
  }

  // Glow + color grade, then opaque procedural background.
  col *= uBrightness * uColor;
  oColor = vec4(col, 1.0);
}
`;

export const GODRAYS_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;          // seconds, monotonically increasing
uniform vec2 uResolution;     // framebuffer size in pixels
uniform vec3 uLightColor;     // ray tint (linear-ish RGB, 0..1)
uniform float uRayCount;      // number of ray bands
uniform float uRaySpeed;      // drift speed
uniform float uRayIntensity;  // overall brightness / additive strength
uniform float uRaySoftness;   // edge falloff exponent (higher = crisper shafts)
uniform float uTopGlow;       // extra glow concentrated near the top
uniform float uFadeDistance;  // vertical falloff from the top
uniform float uWobbleAmount;  // horizontal wobble magnitude
uniform float uWobbleSpeed;   // wobble animation speed

in highp vec2 vUv;
out vec4 oColor;

float hash(float n) {
    return fract(sin(n) * 43758.5453123);
}

float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);

    f = f * f * (3.0 - 2.0 * f);

    float a = hash(i.x + i.y * 57.0);
    float b = hash(i.x + 1.0 + i.y * 57.0);
    float c = hash(i.x + (i.y + 1.0) * 57.0);
    float d = hash(i.x + 1.0 + (i.y + 1.0) * 57.0);

    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

void main() {
    // vUv is already 0..1 with bottom-left origin; this is the Shadertoy \`uv\`.
    vec2 uv = vUv;

    float aspect = uResolution.x / uResolution.y;
    vec2 p = uv;
    p.x = (p.x - 0.5) * aspect + 0.5;

    float t = uTime;
    float fromTop = 1.0 - uv.y;

    float verticalFade = exp(-fromTop * uFadeDistance);
    float topGlow = exp(-fromTop * 8.0) * uTopGlow;

    float wobble =
        (noise(vec2(uv.y * 3.0, t * uWobbleSpeed)) - 0.5) * uWobbleAmount;

    float rayCoord = (p.x + wobble) * uRayCount;

    float raysA = sin(rayCoord + t * uRaySpeed);
    float raysB = sin(rayCoord * 1.73 - t * uRaySpeed * 0.7);

    float rays = raysA * 0.65 + raysB * 0.35;
    rays = rays * 0.5 + 0.5;
    rays = pow(rays, uRaySoftness);

    float shimmer = noise(vec2(uv.x * 10.0, uv.y * 4.0 - t * 0.3));
    rays *= mix(0.75, 1.25, shimmer);

    float alpha = rays * verticalFade * uRayIntensity;
    alpha += topGlow * uRayIntensity;
    alpha = clamp(alpha, 0.0, 1.0);

    // Premultiplied additive output: rgb already scaled by alpha.
    vec3 rayColor = uLightColor * alpha;
    oColor = vec4(rayColor, alpha);
}
`;

export const FIREFLIES_FRAG_SRC = `#version 300 es
precision highp float;

uniform float uTime;
uniform vec2 uResolution;
uniform float uGlowSize;
uniform float uDotSize;
uniform float uSpeed;
uniform float uTwinkle;
uniform vec3 uColor;

in highp vec2 vUv;
out vec4 oColor;

#define FIREFLY_COUNT 36

float hash(float n) {
    return fract(sin(n) * 43758.5453123);
}

vec2 fireflyPos(float id, float t) {
    vec2 base = vec2(hash(id * 12.7), hash(id * 31.3));
    float a = hash(id * 5.1) * 6.28318;
    float b = hash(id * 9.7) * 6.28318;
    vec2 drift = vec2(sin(t * uSpeed + a), cos(t * uSpeed * 0.73 + b)) * 0.12;
    return fract(base + drift);
}

void main() {
    vec2 uv = vUv;
    vec2 p = uv;
    p.x *= uResolution.x / uResolution.y;
    vec3 color = vec3(0.0);
    float alpha = 0.0;
    for (int i = 0; i < FIREFLY_COUNT; i++) {
        float id = float(i);
        vec2 pos = fireflyPos(id, uTime);
        pos.x *= uResolution.x / uResolution.y;
        float d = length(p - pos);
        float phase = hash(id * 17.1) * 6.28318;
        float pulse = 0.5 + 0.5 * sin(uTime * uTwinkle + phase);
        pulse = pulse * pulse * sqrt(pulse);  // pow(pulse, 2.5): a non-integer pow is ~2 transcendentals on mobile; this is 1 sqrt + 2 muls
        float glow = exp(-d * d / (uGlowSize * uGlowSize));
        float core = smoothstep(uDotSize, 0.0, d);
        float intensity = pulse * (glow * 0.55 + core * 1.4);
        color += uColor * intensity;
        alpha += intensity * 0.55;
    }
    alpha = clamp(alpha, 0.0, 1.0);
    color = clamp(color, 0.0, 1.0);
    oColor = vec4(color, alpha);
}
`;

